{"content": "@import "tailwindcss";

@theme {
  --color-primary: #8B0000;
  --color-primary-light: #CD5C5C;
  --color-primary-dark: #5C0000;
  --color-accent: #D4AF37;
  --color-accent-light: #F0D060;
  --color-accent-dark: #B89430;
  --color-background: #0D0D0D;
  --color-surface: #1A1A1A;
  --color-surface-alt: #222222;
  --color-surface-light: #2A2A2A;
  --color-text: #F5F0E8;
  --color-text-light: #D0C8B8;
  --color-text-muted: #888080;
  --color-border: #333333;
  --font-body: "Inter", system-ui, sans-serif;
  --font-heading: "Playfair Display", Georgia, serif;
  --font-menu: "Inter", system-ui, sans-serif;
}

@layer components {
  .container-page {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 1.5rem;
  }
  .section-padding {
    padding: 5rem 0;
  }
  .section-padding-sm {
    padding: 3rem 0;
  }
  .gradient-primary {
    background: linear-gradient(135deg, var(--color-primary), var(--color-primary-dark));
  }
  .gradient-accent {
    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-dark));
  }
  .gradient-hero {
    background: linear-gradient(to bottom, rgba(0,0,0,0.3), rgba(0,0,0,0.85));
  }
  .text-gold {
    color: var(--color-accent);
  }
  .border-gold {
    border-color: var(--color-accent);
  }
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 8px;
}
::-webkit-scrollbar-track {
  background: var(--color-background);
}
::-webkit-scrollbar-thumb {
  background: var(--color-primary);
  border-radius: 4px;
}

/* Smooth scroll */
html {
  scroll-behavior: smooth;
}

body {
  background-color: var(--color-background);
  color: var(--color-text);
  font-family: var(--font-body);
}
